3380                                                KnownFPClass &Known,
3381                                                unsigned Depth) {
3382   Use &U = I->getOperandUse(OpNo);
3383   Value *V = U.get();
3384   Type *VTy = V->getType();
3385 
3386   if (DemandedMask == fcNone) {
3387     if (isa<UndefValue>(V))
3388       return false;
3389     replaceUse(U, PoisonValue::get(VTy));
3390     return true;
3391   }
3392 
3393   // Handle constant
3394   Instruction *VInst = dyn_cast<Instruction>(V);
3395   if (!VInst) {
3396     // Handle constants and arguments
3397     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3398     Known.knownNot(~DemandedMask);
3399 
3400     if (Known.KnownFPClasses == fcNone) {
3401       if (isa<UndefValue>(V))
3402         return false;
3403       replaceUse(U, PoisonValue::get(VTy));
3404       return true;
3405     }
3406 
3407     // Do not try to replace values which are already constants (unless we are
3408     // folding to poison). Doing so could promote poison elements to non-poison
3409     // constants.
3410     if (isa<Constant>(V))
3411       return false;
3412 
3413     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3414     if (!FoldedToConst || FoldedToConst == V)
3415       return false;
3416 
3417     replaceUse(U, FoldedToConst);
3418     return true;
3419   }
3420 
3421   if (Depth == MaxAnalysisRecursionDepth)
3422     return false;
3423 
3424   Value *NewVal;
3425 
3426   if (VInst->hasOneUse()) {
3427     // If the instruction has one use, we can directly simplify it.
3428     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3429   } else {
3430     // If there are multiple uses of this instruction, then we can simplify
3431     // VInst to some other value, but not modify the instruction.
3432     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3433                                                 Depth);
3434   }
3435 
3436   if (!NewVal)
3437     return false;
3438   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3439     salvageDebugInfo(*OpInst);
3440 
3441   replaceUse(U, NewVal);
3442   return true;
3443 }
